@push('scripts')
<script>
function weeklyPlanDraft(drafts, customers) {
    const blank = () => ({ title:'', address:'', customer_id:'', type:'service', service_minutes:30, priority:3, window_start:'', window_end:'', contact_name:'', contact_phone:'', access_notes:'', parking_notes:'', notes:'' });
    return { drafts, customers, templateSearch:'', draftOpen:false, savingDraft:false, draftError:'', draft:blank(), weekdays:[{value:1,label:'Mo'},{value:2,label:'Di'},{value:3,label:'Mi'},{value:4,label:'Do'},{value:5,label:'Fr'},{value:6,label:'Sa'},{value:7,label:'So'}], selectedDays:[1,2,3,4,5], equalShare:true, allowMultiple:false, toggleDay(day) { if (this.selectedDays.includes(day)) { if (this.selectedDays.length > 1) this.selectedDays=this.selectedDays.filter(value=>value!==day); return; } this.selectedDays=[...this.selectedDays, day].sort(); }, matches(value) { return value.toLocaleLowerCase().includes(this.templateSearch.trim().toLocaleLowerCase()); }, preloadCustomer() { const customer=this.customers.find(item=>String(item.id)===String(this.draft.customer_id)); if (!customer) return; this.draft.address=customer.address||''; this.draft.contact_name=customer.name||''; this.draft.contact_phone=customer.phone||''; }, async addDraft() { this.savingDraft=true; this.draftError=''; try { const response=await axios.post(@js(route('sck.routen.draft-stopps.store')), this.draft); this.drafts.push(response.data.stop); this.draftOpen=false; this.draft=blank(); } catch (error) { this.draftError=error.response?.data?.message||'Stopp konnte nicht gespeichert werden.'; } finally { this.savingDraft=false; } } };
}
</script>
